const input = $input.item.json;

// Parsear datos del lead del JSON string
let d = {};
try {
  d = typeof input.datos_lead_json === 'string' 
    ? JSON.parse(input.datos_lead_json) 
    : input.datos_lead_json || {};
} catch(e) {
  d = {};
}

// Normalizar campos con defaults seguros
const lead = {
  ig_user_id: input.ig_user_id || '',
  ig_username: input.ig_username || '',
  nombre: d.nombre_completo || d.nombre || 'Sin nombre',
  telefono: d.telefono_movil || d.telefono || '',
  email: d.email || '',
  preferencia_contacto: d.preferencia_contacto || 'whatsapp',

  // Bloque A - Criterios Basicos
  tipo_contrato: (d.tipo_contrato || '').toLowerCase(),
  antiguedad_anios: parseFloat(d.antiguedad_anios) || 0,
  ingresos_mensuales: parseFloat(d.ingresos_mensuales_netos) || 0,
  sector_empresa: (d.sector_empresa || '').toLowerCase(),
  importe_solicitado: parseFloat(d.importe_solicitado) || 0,
  precio_vivienda: parseFloat(d.precio_vivienda) || 0,
  otras_deudas_mensuales: parseFloat(d.otras_deudas_mensuales) || 0,
  porcentaje_ahorros: d.porcentaje_ahorros || '0-5%',
  estado_busqueda: (d.estado_busqueda || 'solo mirando').toLowerCase(),
  urgencia_hipoteca: (d.urgencia_hipoteca || 'mas 3 meses').toLowerCase(),
  hipoteca_anterior: d.hipoteca_anterior === 'si',
  tipo_documentacion: (d.tipo_documentacion || 'dni').toLowerCase(),

  // Seniales premium
  es_funcionario_o_gran_empresa: d.es_funcionario_o_gran_empresa === true || (d.tipo_contrato || '').toLowerCase() === 'funcionario',
  tiene_cotitular: d.tiene_cotitular === true,
  menor_35_primera_vivienda: d.menor_35_primera_vivienda === true,
  interes_seguros: d.interes_seguros === true,
  es_referido: d.es_referido === true,
  cirbe_limpio: d.cirbe_limpio !== false, // asumimos limpio si no se menciona lo contrario
  tiene_patrimonio: d.tiene_patrimonio === true,

  // Banderas rojas
  impagos_asnef_rai: d.impagos_asnef_rai === true,
  cambio_empleo_reciente: d.cambio_empleo_reciente === true,
  ingresos_irregulares_mayoria: d.ingresos_irregulares_mayoria === true,
  conflicto_legal: d.conflicto_legal === true,
  tarjetas_limite_mas3: d.tarjetas_limite_mas3 === true
};

return lead;

const l = $input.item.json;

let knockout = false;
let knockout_motivo = null;
let knockout_accion = null;

// Filtro 1: Tipo de contrato
if (!l.tipo_contrato || l.tipo_contrato === 'sin contrato' || l.tipo_contrato === 'en paro' || l.tipo_contrato === 'otro') {
  knockout = true;
  knockout_motivo = 'Sin contrato o en paro';
  knockout_accion = 'lista_futuro';
}

// Filtro 2: LTV > 90%
if (!knockout && l.precio_vivienda > 0) {
  const ltv = l.importe_solicitado / l.precio_vivienda;
  if (ltv > 0.90) {
    knockout = true;
    knockout_motivo = `LTV del ${Math.round(ltv*100)}% supera el 90% — deficit de entrada`;
    knockout_accion = 'lista_futuro';
  }
}

// Filtro 3: Ratio endeudamiento > 30%
if (!knockout && l.ingresos_mensuales > 0) {
  // Estimacion cuota hipotecaria: ~0.4% del capital al mes (aproximacion)
  const cuotaHipotecaEst = l.importe_solicitado * 0.004;
  const deudaTotal = l.otras_deudas_mensuales + cuotaHipotecaEst;
  const ratioDeuda = deudaTotal / l.ingresos_mensuales;
  if (ratioDeuda > 0.30) {
    knockout = true;
    knockout_motivo = `Ratio endeudamiento ${Math.round(ratioDeuda*100)}% supera el 30%`;
    knockout_accion = 'ajustar_o_descartar';
  }
}

// Filtro 4: Documentacion
if (!knockout && l.tipo_documentacion === 'sin documentacion') {
  knockout = true;
  knockout_motivo = 'Sin documentacion espaniola';
  knockout_accion = 'gestoria_no_residentes';
}

// Banderas Rojas (Nivel 4.3) — descalificacion inmediata
if (!knockout && l.impagos_asnef_rai) {
  knockout = true;
  knockout_motivo = 'Impagos activos en ASNEF o RAI';
  knockout_accion = 'descarte_inmediato';
}
if (!knockout && l.cambio_empleo_reciente) {
  knockout = true;
  knockout_motivo = 'Cambio de empleo en los ultimos 6 meses';
  knockout_accion = 'lista_futuro';
}
if (!knockout && l.ingresos_irregulares_mayoria) {
  knockout = true;
  knockout_motivo = 'Mas del 50% de ingresos irregulares (comisiones/propinas)';
  knockout_accion = 'lista_futuro';
}
if (!knockout && l.conflicto_legal) {
  knockout = true;
  knockout_motivo = 'Conflicto legal pendiente (divorcio/herencia/embargo)';
  knockout_accion = 'lista_futuro';
}
if (!knockout && l.tarjetas_limite_mas3) {
  knockout = true;
  knockout_motivo = 'Mas de 3 tarjetas de credito al limite';
  knockout_accion = 'lista_futuro';
}

return {
  ...l,
  knockout,
  knockout_motivo,
  knockout_accion
};

const l = $input.item.json;
let score = 0;
const detalle = {};

// ============================================
// BLOQUE A — Criterios Basicos (max 60 pts)
// ============================================

// Tipo de contrato (15 pts)
let ptsContrato = 0;
if (l.tipo_contrato === 'indefinido') ptsContrato = 15;
else if (l.tipo_contrato === 'funcionario') ptsContrato = 15;
else if ((l.tipo_contrato === 'temporal' || l.tipo_contrato === 'autonomo') && l.antiguedad_anios >= 2) ptsContrato = 8;
else if (l.tipo_contrato === 'autonomo') ptsContrato = 5;
score += ptsContrato;
detalle.contrato = ptsContrato;

// Antiguedad (15 pts)
let ptsAnt = 0;
if (l.antiguedad_anios >= 5) ptsAnt = 15;
else if (l.antiguedad_anios >= 2) ptsAnt = 10;
score += ptsAnt;
detalle.antiguedad = ptsAnt;

// Ratio endeudamiento (15 pts)
let ptsDeuda = 0;
const cuotaHipEst = l.importe_solicitado * 0.004;
const deudaTotalMes = l.otras_deudas_mensuales + cuotaHipEst;
const ratioDeuda = l.ingresos_mensuales > 0 ? deudaTotalMes / l.ingresos_mensuales : 1;
if (ratioDeuda < 0.20) ptsDeuda = 15;
else if (ratioDeuda < 0.25) ptsDeuda = 10;
else if (ratioDeuda < 0.30) ptsDeuda = 5;
score += ptsDeuda;
detalle.ratio_deuda = ptsDeuda;
detalle.ratio_deuda_pct = Math.round(ratioDeuda * 100);

// LTV (10 pts)
let ptsLTV = 0;
const ltv = l.precio_vivienda > 0 ? l.importe_solicitado / l.precio_vivienda : 1;
if (ltv < 0.80) ptsLTV = 10;
else if (ltv < 0.85) ptsLTV = 7;
else if (ltv < 0.90) ptsLTV = 5;
score += ptsLTV;
detalle.ltv = ptsLTV;
detalle.ltv_pct = Math.round(ltv * 100);

// Documentacion (5 pts)
let ptsDoc = 0;
if (l.tipo_documentacion === 'dni') ptsDoc = 5;
else if (l.tipo_documentacion === 'nie') ptsDoc = 2;
score += ptsDoc;
detalle.documentacion = ptsDoc;

// ============================================
// BLOQUE B — Criterios Premium (max 40 pts)
// ============================================

// Funcionario o gran empresa (+10)
if (l.es_funcionario_o_gran_empresa) { score += 10; detalle.premium_funcionario = 10; }

// CIRBE limpio (+8)
if (l.cirbe_limpio) { score += 8; detalle.premium_cirbe = 8; }

// Ahorros >20% del precio total (+7)
const ahorrosMap = { '0-5%': 0.025, '5-10%': 0.075, '10-20%': 0.15, 'mas 20%': 0.25 };
const ahorrosPct = ahorrosMap[l.porcentaje_ahorros] || 0;
if (ahorrosPct >= 0.20) { score += 7; detalle.premium_ahorros = 7; }

// Pareja o cotitular (+5)
if (l.tiene_cotitular) { score += 5; detalle.premium_cotitular = 5; }

// Sector estrategico (+5)
const sectoresEst = ['tecnologia', 'sanidad', 'banca', 'educacion', 'tech', 'salud'];
if (sectoresEst.some(s => (l.sector_empresa || '').includes(s))) {
  score += 5; detalle.premium_sector = 5;
}

// Lead referido (+5)
if (l.es_referido) { score += 5; detalle.premium_referido = 5; }

// ============================================
// NIVEL 4.1 — Filtro de Intencion Real
// ============================================

// Estado busqueda
if (l.estado_busqueda === 'reserva firmada' || l.estado_busqueda === 'reserva ya firmada') { score += 30; detalle.intencion_reserva = 30; }
else if (l.estado_busqueda === 'vivienda identificada') { score += 5; detalle.intencion_vivienda_id = 5; }
else { score -= 10; detalle.intencion_solo_mirando = -10; }

// Urgencia
if (l.urgencia_hipoteca === 'menos 1 mes' || l.urgencia_hipoteca === 'menos de 1 mes') { score += 15; detalle.urgencia_alta = 15; }
else if (l.urgencia_hipoteca === '1-3 meses') { score += 0; }
else { score -= 5; detalle.urgencia_baja = -5; }

// ============================================
// NIVEL 4.4 — Valor de Vida del Cliente
// ============================================

if (l.menor_35_primera_vivienda) { score += 10; detalle.valor_joven = 10; }
if (l.precio_vivienda > 300000) { score += 10; detalle.valor_precio_alto = 10; }
if (l.interes_seguros) { score += 8; detalle.valor_seguros = 8; }
if (l.tiene_patrimonio) { score += 7; detalle.valor_patrimonio = 7; }

// Score final (clampar 0-100 para la clasificacion base, pero dejamos el real)
const scoreFinal = Math.max(0, score);
const scoreDisplay = Math.min(100, scoreFinal);

// Clasificacion
let clasificacion;
if (scoreDisplay >= 80) clasificacion = 'A';
else if (scoreDisplay >= 60) clasificacion = 'B';
else if (scoreDisplay >= 40) clasificacion = 'C';
else clasificacion = 'D';

return {
  ...l,
  score: scoreDisplay,
  score_real: scoreFinal,
  clasificacion,
  detalle_scoring: JSON.stringify(detalle)
};
